```typescript
export type ProjectState =
  | { status: "none" }
  | { status: "planned"; id: string; name: string }
  | { status: "active"; id: string; name: string; startedAt: string }
  | { status: "completed"; id: string; name: string; completedAt: string }
  | { status: "archived"; id: string };

export type ProjectCommand =
  | { type: "plan"; id: string; name: string }
  | { type: "start"; at: string }
  | { type: "complete"; at: string }
  | { type: "archive" };

export type ProjectEvent =
  | { type: "ProjectPlanned"; id: string; name: string }
  | { type: "ProjectStarted"; at: string }
  | { type: "ProjectCompleted"; at: string }
  | { type: "ProjectArchived" };

export class ProjectError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const projectDecider: Decider<ProjectCommand, ProjectEvent, ProjectState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new ProjectError("ALREADY_PLANNED");
        return [{ type: "ProjectPlanned", id: command.id, name: command.name }];
      case "start":
        if (state.status === "completed") throw new ProjectError("ALREADY_COMPLETED");
        if (state.status !== "planned") throw new ProjectError("NOT_PLANNED");
        return [{ type: "ProjectStarted", at: command.at }];
      case "complete":
        if (state.status !== "active") throw new ProjectError("NOT_ACTIVE");
        return [{ type: "ProjectCompleted", at: command.at }];
      case "archive":
        if (state.status !== "completed") throw new ProjectError("NOT_COMPLETED");
        return [{ type: "ProjectArchived" }];
      default: {
        const _n: never = command;
        throw new ProjectError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "ProjectPlanned":
        return { status: "planned", id: event.id, name: event.name };
      case "ProjectStarted":
        if (state.status !== "planned") return state;
        return { status: "active", id: state.id, name: state.name, startedAt: event.at };
      case "ProjectCompleted":
        if (state.status !== "active") return state;
        return { status: "completed", id: state.id, name: state.name, completedAt: event.at };
      case "ProjectArchived":
        if (state.status !== "completed") return state;
        return { status: "archived", id: state.id };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

A Decider pairs a pure `decide(command, state)` with a pure `evolve(state, event)` and a literal `initialState`. `decide` validates invariants and produces events; `evolve` folds events back into state. No I/O, fully deterministic.

```typescript
export type SprintState =
  | { status: "none" }
  | { status: "active"; id: string; goal: string; points: number }
  | { status: "closed"; id: string; finalPoints: number };

export type SprintCommand =
  | { type: "begin"; id: string; goal: string }
  | { type: "addStoryPoints"; points: number }
  | { type: "close" };

export type SprintEvent =
  | { type: "SprintBegun"; id: string; goal: string }
  | { type: "StoryPointsAdded"; points: number }
  | { type: "SprintClosed"; finalPoints: number };

export class SprintError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const sprintDecider: Decider<SprintCommand, SprintEvent, SprintState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "begin":
        if (s.status !== "none") throw new SprintError("ALREADY_BEGUN");
        return [{ type: "SprintBegun", id: c.id, goal: c.goal }];
      case "addStoryPoints":
        if (s.status !== "active") throw new SprintError("NOT_ACTIVE");
        if (c.points <= 0) throw new SprintError("INVALID_POINTS");
        return [{ type: "StoryPointsAdded", points: c.points }];
      case "close":
        if (s.status !== "active") throw new SprintError("NOT_ACTIVE");
        return [{ type: "SprintClosed", finalPoints: s.points }];
      default: {
        const _n: never = c;
        throw new SprintError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "SprintBegun":
        return { status: "active", id: e.id, goal: e.goal, points: 0 };
      case "StoryPointsAdded":
        if (s.status !== "active") return s;
        return { ...s, points: s.points + e.points };
      case "SprintClosed":
        if (s.status !== "active") return s;
        return { status: "closed", id: s.id, finalPoints: e.finalPoints };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
