```typescript
export type WorkOrderEvent =
  | { type: "WorkOrderRaised"; id: string; requester: string; priority: "low" | "high" }
  | { type: "WorkOrderScheduled"; technician: string; at: string }
  | { type: "WorkOrderStarted"; at: string }
  | { type: "WorkOrderCompleted"; at: string; notes: string }
  | { type: "WorkOrderAudited"; auditor: string };

export type WorkOrderView = Readonly<{
  id: string;
  requester: string;
  technician: string | null;
  status: "raised" | "scheduled" | "inProgress" | "completed";
  priority: "low" | "high";
  startedAt: string | null;
  completedAt: string | null;
}>;

export const emptyView: WorkOrderView = {
  id: "",
  requester: "",
  technician: null,
  status: "raised",
  priority: "low",
  startedAt: null,
  completedAt: null,
};

export function project(view: WorkOrderView, event: WorkOrderEvent): WorkOrderView {
  switch (event.type) {
    case "WorkOrderRaised":
      return { ...emptyView, id: event.id, requester: event.requester, priority: event.priority };
    case "WorkOrderScheduled":
      return { ...view, technician: event.technician, status: "scheduled" };
    case "WorkOrderStarted":
      return { ...view, status: "inProgress", startedAt: event.at };
    case "WorkOrderCompleted":
      return { ...view, status: "completed", completedAt: event.at };
    case "WorkOrderAudited":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function workOrderViewFrom(events: WorkOrderEvent[]): WorkOrderView {
  return events.reduce(project, emptyView);
}
