```typescript
export type LedgerEvent =
  | { type: "AccountOpened"; accountId: string; owner: string }
  | { type: "FundsCredited"; accountId: string; amount: number }
  | { type: "FundsDebited"; accountId: string; amount: number }
  | { type: "AccountFrozen"; accountId: string }
  | { type: "AccountClosed"; accountId: string };

export type LedgerView = Readonly<{
  balances: Readonly<Record<string, number>>;
  owners: Readonly<Record<string, string>>;
  frozen: Readonly<Record<string, boolean>>;
}>;

export const emptyLedger: LedgerView = {
  balances: {},
  owners: {},
  frozen: {},
};

export function project(view: LedgerView, event: LedgerEvent): LedgerView {
  switch (event.type) {
    case "AccountOpened":
      return {
        balances: { ...view.balances, [event.accountId]: 0 },
        owners: { ...view.owners, [event.accountId]: event.owner },
        frozen: { ...view.frozen, [event.accountId]: false },
      };
    case "FundsCredited": {
      const current = view.balances[event.accountId] ?? 0;
      return { ...view, balances: { ...view.balances, [event.accountId]: current + event.amount } };
    }
    case "FundsDebited": {
      const current = view.balances[event.accountId] ?? 0;
      return { ...view, balances: { ...view.balances, [event.accountId]: current - event.amount } };
    }
    case "AccountFrozen":
      return { ...view, frozen: { ...view.frozen, [event.accountId]: true } };
    case "AccountClosed": {
      const balances: Record<string, number> = { ...view.balances };
      delete balances[event.accountId];
      const owners: Record<string, string> = { ...view.owners };
      delete owners[event.accountId];
      const frozen: Record<string, boolean> = { ...view.frozen };
      delete frozen[event.accountId];
      return { balances, owners, frozen };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function ledgerFrom(events: LedgerEvent[]): LedgerView {
  return events.reduce(project, emptyLedger);
}
```

```typescript
export type BacklogEvent =
  | { type: "TicketFiled"; id: string }
  | { type: "TicketTriaged"; id: string; priority: "low" | "high" }
  | { type: "TicketResolved"; id: string }
  | { type: "TicketReopened"; id: string }
  | { type: "TicketCommented"; id: string; author: string };

export type BacklogView = Readonly<{
  openCount: number;
  resolvedCount: number;
  reopenedCount: number;
  lastFiledId: string | null;
}>;

export const emptyBacklog: BacklogView = {
  openCount: 0,
  resolvedCount: 0,
  reopenedCount: 0,
  lastFiledId: null,
};

export function project(view: BacklogView, event: BacklogEvent): BacklogView {
  switch (event.type) {
    case "TicketFiled":
      return { ...view, openCount: view.openCount + 1, lastFiledId: event.id };
    case "TicketResolved":
      return {
        ...view,
        openCount: Math.max(0, view.openCount - 1),
        resolvedCount: view.resolvedCount + 1,
      };
    case "TicketReopened":
      return {
        ...view,
        resolvedCount: Math.max(0, view.resolvedCount - 1),
        openCount: view.openCount + 1,
        reopenedCount: view.reopenedCount + 1,
      };
    case "TicketTriaged":
    case "TicketCommented":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function backlogFrom(events: BacklogEvent[]): BacklogView {
  return events.reduce(project, emptyBacklog);
}
```

```typescript
export type AllocationEvent =
  | { type: "HoursAllocated"; taskId: string; assignee: string; hours: number }
  | { type: "HoursReassigned"; taskId: string; fromAssignee: string; toAssignee: string }
  | { type: "HoursReleased"; taskId: string; assignee: string; hours: number }
  | { type: "TaskNoteAdded"; taskId: string; note: string };

export type AllocationView = Readonly<{
  hoursByAssignee: Readonly<Record<string, number>>;
  taskAssignee: Readonly<Record<string, string>>;
  taskHours: Readonly<Record<string, number>>;
}>;

export const emptyAllocation: AllocationView = {
  hoursByAssignee: {},
  taskAssignee: {},
  taskHours: {},
};

export function project(view: AllocationView, event: AllocationEvent): AllocationView {
  switch (event.type) {
    case "HoursAllocated": {
      const prior = view.hoursByAssignee[event.assignee] ?? 0;
      return {
        hoursByAssignee: { ...view.hoursByAssignee, [event.assignee]: prior + event.hours },
        taskAssignee: { ...view.taskAssignee, [event.taskId]: event.assignee },
        taskHours: { ...view.taskHours, [event.taskId]: event.hours },
      };
    }
    case "HoursReassigned": {
      const hours = view.taskHours[event.taskId] ?? 0;
      const fromPrior = view.hoursByAssignee[event.fromAssignee] ?? 0;
      const toPrior = view.hoursByAssignee[event.toAssignee] ?? 0;
      return {
        hoursByAssignee: {
          ...view.hoursByAssignee,
          [event.fromAssignee]: fromPrior - hours,
          [event.toAssignee]: toPrior + hours,
        },
        taskAssignee: { ...view.taskAssignee, [event.taskId]: event.toAssignee },
        taskHours: view.taskHours,
      };
    }
    case "HoursReleased": {
      const prior = view.hoursByAssignee[event.assignee] ?? 0;
      return { ...view, hoursByAssignee: { ...view.hoursByAssignee, [event.assignee]: prior - event.hours } };
    }
    case "TaskNoteAdded":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function allocationFrom(events: AllocationEvent[]): AllocationView {
  return events.reduce(project, emptyAllocation);
}
```

```typescript
export type Snapshot<S> = { version: number; state: S };

export type JournalV1 = { id: string; entries: number };
export type JournalV2 = { id: string; entries: number; lastEntryAt: string | null };
export type JournalV3 = {
  id: string;
  entries: number;
  lastEntryAt: string | null;
  status: "open" | "closed";
};

export type CurrentJournal = JournalV3;
export const CURRENT_VERSION = 3;

export class JournalSnapshotError extends Error {}

function v1Tov2(s: JournalV1): JournalV2 {
  return { ...s, lastEntryAt: null };
}

function v2Tov3(s: JournalV2): JournalV3 {
  return { ...s, status: "open" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentJournal> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new JournalSnapshotError(`UNSUPPORTED_VERSION_${version}`);
  }
  if (version === 1) {
    state = v1Tov2(state as JournalV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as JournalV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new JournalSnapshotError("UPGRADE_INCOMPLETE");
  }
  const upgraded = state as CurrentJournal;
  if (typeof upgraded.id !== "string" || typeof upgraded.entries !== "number") {
    throw new JournalSnapshotError("SHAPE_MISMATCH");
  }
  return { version, state: upgraded };
}

export function loadJournal(raw: Snapshot<unknown>): CurrentJournal {
  return upgradeSnapshot(raw).state;
}
```

Store each snapshot as `{ version, state }`. At load time, run upgraders until you reach CURRENT_VERSION and then assert the final shape. Each step returns a new object rather than mutating the stored blob.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type SprintV1 = { id: string; goal: string };
export type SprintV2 = { id: string; goal: string; points: number };
export type SprintV3 = {
  id: string;
  goal: string;
  points: number;
  status: "active" | "closed";
};

export type CurrentSprint = SprintV3;
export const CURRENT_VERSION = 3;

class SprintUpgradeError extends Error {}

function v1Tov2(s: SprintV1): SprintV2 {
  return { ...s, points: 0 };
}

function v2Tov3(s: SprintV2): SprintV3 {
  return { ...s, status: "active" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentSprint> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) {
    s = v1Tov2(s as SprintV1);
    v = 2;
  }
  if (v === 2) {
    s = v2Tov3(s as SprintV2);
    v = 3;
  }
  if (v !== CURRENT_VERSION) throw new SprintUpgradeError("UNSUPPORTED");
  const out = s as CurrentSprint;
  if (typeof out.id !== "string" || typeof out.points !== "number") {
    throw new SprintUpgradeError("SHAPE");
  }
  return { version: v, state: out };
}

export function loadSprint(raw: Snapshot<unknown>): CurrentSprint {
  return upgradeSnapshot(raw).state;
}
