export class ConcurrencyConflict extends Error {
  constructor(
    public readonly stream: string,
    public readonly expected: ExpectedRevision,
    public readonly actual: bigint | null,
  ) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export function isConcurrencyError(err: unknown): boolean {
  return err instanceof Error && err.message.toUpperCase().includes("WRONG_EXPECTED_VERSION");
}

export async function appendTicketEvents(
  store: EventStore<TicketEvent>,
  stream: string,
  events: readonly TicketEvent[],
): Promise<bigint> {
  const { revision } = await store.readStream(stream);
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  try {
    const result = await store.appendToStream(stream, events, { expectedRevision });
    return result.nextExpectedRevision;
  } catch (err) {
    if (isConcurrencyError(err)) {
      throw new ConcurrencyConflict(stream, expectedRevision, revision);
    }
    throw err;
  }
}
