export type TaskEvent =
  | { type: "task-created"; data: { id: string; summary: string } }
  | { type: "task-assigned"; data: { assignee: string } }
  | { type: "task-completed"; data: { at: string } };

export type Task = Readonly<{
  id: string;
  summary: string;
  assignee: string | null;
  completedAt: string | null;
}>;

export function when(
  current: Partial<Task>,
  event: TaskEvent,
): Partial<Task> {
  switch (event.type) {
    case "task-created":
      return { id: event.data.id, summary: event.data.summary, assignee: null, completedAt: null };
    case "task-assigned":
      return { ...current, assignee: event.data.assignee };
    case "task-completed":
      return { ...current, completedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function isTask(v: Partial<Task>): v is Task {
  return (
    typeof v.id === "string" && v.id.length > 0 &&
    typeof v.summary === "string" &&
    (v.assignee === null || typeof v.assignee === "string") &&
    (v.completedAt === null || typeof v.completedAt === "string")
  );
}

export function aggregateStream<A, E>(
  events: readonly E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const s = events.reduce<Partial<A>>(reducer, {});
  if (!check(s)) throw new Error("INVALID_STATE");
  return s;
}

export function taskFrom(events: TaskEvent[]): Task {
  return aggregateStream(events, when, isTask);
}
