  store: EventStore,
  streamName: string,
  command: TicketCommand,
): Promise<void> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, { status: "none" } as TicketState);
  const produced = decide(command, state);
  if (produced.length === 0) return;
  await store.appendToStream(streamName, produced, { expectedRevision: revision ?? "no_stream" });
}

// read side - eventually consistent with the event store, populated by a subscription
export async function queryView(read: ReadStore, id: string): Promise<TicketListingView | null> {
  return read.getById(id);
