import { Effect } from "effect";

export type BacklogEntryState =
  | { status: "none" }
  | { status: "queued"; id: string; summary: string; priority: number }
  | { status: "pulled"; id: string; summary: string; pulledAt: string }
  | { status: "removed"; id: string };

export type BacklogEntryCommand =
  | { type: "queue"; id: string; summary: string; priority: number }
  | { type: "pull"; at: string }
  | { type: "remove"; reason: string };

export type BacklogEntryEvent =
  | { type: "EntryQueued"; id: string; summary: string; priority: number }
  | { type: "EntryPulled"; at: string }
  | { type: "EntryRemoved"; reason: string };

export class BacklogEntryError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const backlogEntryDecider: Decider<BacklogEntryCommand, BacklogEntryEvent, BacklogEntryState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "queue":
        if (s.status !== "none") throw new BacklogEntryError("EXISTS");
        if (c.priority < 0) throw new BacklogEntryError("INVALID_PRIORITY");
        return [{ type: "EntryQueued", id: c.id, summary: c.summary, priority: c.priority }];
      case "pull":
        if (s.status !== "queued") throw new BacklogEntryError("NOT_QUEUED");
        return [{ type: "EntryPulled", at: c.at }];
      case "remove":
        if (s.status === "removed" || s.status === "none") throw new BacklogEntryError("NOT_FOUND");
        return [{ type: "EntryRemoved", reason: c.reason }];
      default: {
        const _n: never = c;
        throw new BacklogEntryError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "EntryQueued":
        return { status: "queued", id: e.id, summary: e.summary, priority: e.priority };
      case "EntryPulled":
        if (s.status !== "queued") return s;
        return { status: "pulled", id: s.id, summary: s.summary, pulledAt: e.at };
      case "EntryRemoved":
        if (s.status === "none") return s;
        return { status: "removed", id: "id" in s ? s.id : "" };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: BacklogEntryEvent[]; revision: bigint | null }>;
  appendToStream(
    s: string,
    e: readonly BacklogEntryEvent[],
    o: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export const handleBacklogEntry = (
  eventStore: EventStore,
  streamName: string,
  command: BacklogEntryCommand,
) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => eventStore.readStream(streamName));
    const state = events.reduce(backlogEntryDecider.evolve, backlogEntryDecider.initialState);
    const produced = backlogEntryDecider.decide(command, state);
    if (produced.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() => eventStore.appendToStream(streamName, produced, { expectedRevision }));
  });
